import psycopg2

def search_users(**kwargs):
    conn = psycopg2.connect(
        host="localhost",
        database="database_name",
        user="username",
        password="password"
    )
    cur = conn.cursor()

    query = """
        SELECT *
        FROM users
        WHERE 1=1
    """

    params = {}

    if 'username' in kwargs:
        query += " AND username ILIKE %s"
        params['%s'] = '%' + kwargs['username'] + '%'

    if 'email' in kwargs:
        query += " AND email ILIKE %s"
        params['%s'] = '%' + kwargs['email'] + '%'

    if 'role' in kwargs:
        query += " AND role = %s"
        params['%s'] = kwargs['role']

    if 'status' in kwargs:
        query += " AND status = %s"
        params['%s'] = kwargs['status']

    cur.execute(query, params.values())
    results = cur.fetchall()

    conn.close()
    return results

